script:
frappe.ui.form.on('Job Card', {
    workstation: function(frm) {
        if (!frm.doc.workstation || !frm.doc.item_code) return;

        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Workstation Inspection Mapping",
                filters: {
                    item: frm.doc.item_code,
                    workstation: frm.doc.workstation
                },
                fields: ["inspection_template"]
            },
            callback: function(r) {
                if (r.message && r.message.length > 0) {
                    frm.set_value("custom_quality_template", r.message[0].inspection_template);
                } else {
                    frappe.msgprint("No Inspection Template mapped for this Item + Workstation");
                }
            }
        });
    }
});

frappe.ui.form.on('Quality Inspection', {
    quality_inspection_template: function(frm) {
        // Give the system 1 second to finish the standard row generation
        setTimeout(() => {
            frm.doc.readings.forEach(row => {
                // Manually fetch the datatype from the Master
                frappe.db.get_value('Quality Inspection Parameter', row.specification, 'custom_parameter_data_type', (r) => {
                    if (r && r.custom_parameter_data_type) {
                        // Push the value into the row
                        frappe.model.set_value(row.doctype, row.name, 'custom_parameter_data_type', r.custom_parameter_data_type);
                    }
                });
            });
            frm.refresh_field('readings');
        }, 1000);
    }
});
